+    // ── Constants validation ────────────────────────────────────
+
+    #[test]
+    fn constants_are_sensible() {
+        assert_eq!(DEFAULT_RESPONSE_LIMIT_UNAUTHENTICATED, 32);
+        assert_eq!(DEFAULT_RESPONSE_LIMIT_AUTHENTICATED, 1000);
